import React, { useState, useMemo } from "react";
import { 
  theme, 
  Typography, 
  Table, 
  Button, 
  Space, 
  Select, 
  DatePicker,
  Card,
  Badge,
  message
} from "antd";
import { 
  SearchOutlined, 
  FileExcelOutlined,
  HistoryOutlined,
  TableOutlined,
  BarChartOutlined
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import EChart from "@/framework/components/Chart/EChart"; // Use Common Component
import dayjs from "dayjs";
import { PLANTS, mockCameras } from "../../dashboard/data/mockData";

const { Title } = Typography;
const { useToken } = theme;
const { Option } = Select;
const { RangePicker } = DatePicker;

interface StatusHistoryData {
  key: string;
  status: "Online" | "Offline";
  plantName: string;
  cameraName: string;
  address: string;
  ip: string;
  checkTime: string;
  remark: string;
  plantId: number;
  cameraId: number;
}

const allMockHistory: StatusHistoryData[] = Array.from({ length: 200 }, (_, i) => {
  const cam = mockCameras[i % mockCameras.length];
  const plant = PLANTS.find(p => p.id === cam.plantId);
  const isOffline = Math.random() > 0.8; 
  return {
    key: i.toString(),
    status: isOffline ? "Offline" : "Online",
    plantName: plant?.name || `Plant ${cam.plantId}`,
    cameraName: cam.name,
    address: "서울 구로구 디지털로 12-3",
    ip: `192.168.10.${100 + (i % 100)}`,
    checkTime: dayjs().subtract(Math.floor(i / 2), "hour").format("YYYY-MM-DD HH:mm:ss"),
    remark: "-",
    plantId: cam.plantId,
    cameraId: cam.id
  };
});

export default function StatusHistory() {
  const { token } = useToken();
  const { t } = useI18n(["history"]);
  
  const [filterPlant, setFilterPlant] = useState<string>("all");
  const [filterCamera, setFilterCamera] = useState<string>("all");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [filterDates, setFilterDates] = useState<any>([dayjs().subtract(7, "day"), dayjs()]);
  
  const [filteredData, setFilteredData] = useState<StatusHistoryData[]>(allMockHistory);
  const [viewMode, setViewMode] = useState<"table" | "chart">("table");

  const handleSearch = () => {
    let result = [...allMockHistory];
    if (filterPlant !== "all") result = result.filter(it => it.plantId === Number(filterPlant));
    if (filterCamera !== "all") result = result.filter(it => it.cameraId === Number(filterCamera));
    if (filterStatus !== "all") result = result.filter(it => it.status === filterStatus);
    if (filterDates && filterDates.length === 2) {
      const start = filterDates[0].startOf("day");
      const end = filterDates[1].endOf("day");
      result = result.filter(it => {
        const time = dayjs(it.checkTime);
        return time.isAfter(start) && time.isBefore(end);
      });
    }
    setFilteredData(result);
    message.success(t("status.filters.search_success", { count: result.length }));
  };

  const statusPieOption = useMemo(() => {
    const online = filteredData.filter(it => it.status === "Online").length;
    const offline = filteredData.filter(it => it.status === "Offline").length;
    return {
      tooltip: { trigger: "item" },
      legend: { bottom: "5%", left: "center" },
      series: [
        {
          name: t("status.charts.series_name"),
          type: "pie",
          radius: ["40%", "70%"],
          avoidLabelOverlap: false,
          itemStyle: { borderRadius: 10, borderColor: token.colorBgContainer, borderWidth: 2 },
          label: { show: false, position: "center" },
          emphasis: { label: { show: true, fontSize: 20, fontWeight: "bold" } },
          data: [
            { value: online, name: "Online", itemStyle: { color: token.colorSuccess } },
            { value: offline, name: "Offline", itemStyle: { color: token.colorError } }
          ]
        }
      ]
    };
  }, [filteredData, token, t]);

  const plantBarOption = useMemo(() => {
    const categories = PLANTS.map(p => p.name);
    const offlineData = PLANTS.map(p => filteredData.filter(it => it.plantId === p.id && it.status === "Offline").length);
    const onlineData = PLANTS.map(p => filteredData.filter(it => it.plantId === p.id && it.status === "Online").length);

    return {
      tooltip: { trigger: "axis", axisPointer: { type: "shadow" } },
      legend: { top: "5%" },
      grid: { left: "3%", right: "4%", bottom: "3%", containLabel: true },
      xAxis: { type: "value", boundaryGap: [0, 0.01] },
      yAxis: { type: "category", data: categories },
      series: [
        { name: "Online", type: "bar", data: onlineData, itemStyle: { color: token.colorSuccess } },
        { name: "Offline", type: "bar", data: offlineData, itemStyle: { color: token.colorError } }
      ]
    };
  }, [filteredData, token]);

  const columns = [
    { title: t("status.columns.status"), dataIndex: "status", key: "status", width: 120, align: "center" as const, render: (st: string) => <Badge status={st === "Online" ? "success" : "error"} text={st} style={{ fontWeight: 600 }} /> },
    { title: t("status.columns.plant"), dataIndex: "plantName", key: "plantName", width: 170 },
    { title: t("status.columns.camera"), dataIndex: "cameraName", key: "cameraName", ellipsis: true },
    { title: t("status.columns.address"), dataIndex: "address", key: "address", width: 280, ellipsis: true },
    { title: t("status.columns.ip"), dataIndex: "ip", key: "ip", width: 140 },
    { title: t("status.columns.check_time"), dataIndex: "checkTime", key: "checkTime", width: 180 },
    { title: t("status.columns.remark"), dataIndex: "remark", key: "remark", width: 100 },
  ];

  return (
    <div style={{ padding: "20px", background: token.colorBgLayout, minHeight: "100%", display: "flex", flexDirection: "column", gap: 20 }}>
      {/* Filters Card */}
      <Card styles={{ body: { padding: "12px 24px" } }} style={{ border: `1px solid ${token.colorBorderSecondary}` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 16 }}>
          <Space size="middle">
            <Select value={filterPlant} onChange={setFilterPlant} style={{ width: 160, height: 40 }}><Option value="all">{t("status.filters.plant_all")}</Option>{PLANTS.map(p => <Option key={p.id} value={p.id.toString()}>{p.name}</Option>)}</Select>
            <Select value={filterCamera} onChange={setFilterCamera} style={{ width: 160, height: 40 }}><Option value="all">{t("status.filters.camera_all")}</Option>{mockCameras.slice(0, 15).map(c => <Option key={c.id} value={c.id.toString()}>{c.name}</Option>)}</Select>
            <Select value={filterStatus} onChange={setFilterStatus} style={{ width: 120, height: 40 }}><Option value="all">{t("status.filters.status_all")}</Option><Option value="Online">Online</Option><Option value="Offline">Offline</Option></Select>
            <RangePicker value={filterDates} onChange={setFilterDates} style={{ height: 40 }} />
          </Space>
          <Space>
            <Button type="primary" icon={<SearchOutlined />} onClick={handleSearch} style={{ height: 40, width: 100 }}>{t("status.filters.search")}</Button>
            <Button icon={<FileExcelOutlined />} style={{ height: 40 }}>{t("status.filters.excel")}</Button>
            <Space.Compact><Button icon={<TableOutlined />} type={viewMode === "table" ? "primary" : "default"} onClick={() => setViewMode("table")} /><Button icon={<BarChartOutlined />} type={viewMode === "chart" ? "primary" : "default"} onClick={() => setViewMode("chart")} /></Space.Compact>
          </Space>
        </div>
      </Card>

      <div style={{ flex: 1, background: token.colorBgContainer, borderRadius: token.borderRadiusLG, border: `1px solid ${token.colorBorderSecondary}`, overflow: "hidden" }}>
        <div style={{ padding: "16px 24px", borderBottom: `1px solid ${token.colorBorderSecondary}`, display: "flex", alignItems: "center", gap: 10 }}>
          <HistoryOutlined style={{ fontSize: 20, color: token.colorPrimary }} /><Title level={4} style={{ margin: 0 }}>{t("status.title")}</Title>
        </div>
        
        {viewMode === "table" ? (
          <Table columns={columns} dataSource={filteredData} pagination={{ pageSize: 15 }} scroll={{ y: "calc(100vh - 380px)" }} />
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24, padding: 24 }}>
             <Card title={t("status.charts.distribution")} style={{ boxShadow: token.boxShadowSecondary }}>
                <EChart option={statusPieOption} style={{ height: 350, width: "100%" }} />
             </Card>
             <Card title={t("status.charts.plant_usage")} style={{ boxShadow: token.boxShadowSecondary }}>
                <EChart option={plantBarOption} style={{ height: 350, width: "100%" }} />
             </Card>
          </div>
        )}
      </div>
    </div>
  );
}
